use crate::{
    crypto::Cipher,
    packet::{
        Ac215Packet,
        direction::Ac215PacketDirection,
        header::{Ac215Header, ChecksumMode},
        packets::{
            answer_firm_ver::AnswerFirmVer825Packet, manual_output::ManualOutputPacket,
            send_log_message::SendLogMessagePacket, update_clock::UpdateClockPacket,
        },
    },
};

#[tokio::test]
async fn test() {
    let bytes = hex::decode("").unwrap();
    let no_overrides = std::collections::HashMap::new();
    let (header, payload) = Ac215Header::parse_frame(
        Ac215PacketDirection::FromPanel,
        Cipher::new(),
        &mut &bytes[..],
        ChecksumMode::Auto,
        &no_overrides,
    )
    .await
    .unwrap();

    println!("Header: {:#?}", header);
    // println!("Payload: {:02X?}", payload);

    let packet = ManualOutputPacket::from_bytes(&header, &payload).unwrap();

    println!("Packet: {:#?}", packet);
}

